import sys
import boto3

def create_sns_subscription(topic, user_provided_url):
    sns = boto3.client('sns')
    response = sns.subscribe(TopicArn=topic, Protocol='https', Endpoint=user_provided_url)
    print(f'Subscription created with SubscriptionArn: {response["SubscriptionArn"]}')

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python create_sns_subscription.py TOPIC URL")
        sys.exit(1)

    topic = sys.argv[1]
    user_provided_url = sys.argv[2]
    create_sns_subscription(topic, user_provided_url)